CREATE TABLE doctororder (orderid int NOT NULL AUTO_INCREMENT, Rid varchar(15) NOT NULL, ordername varchar(80) DEFAULT NULL, ordertype varchar(45) DEFAULT NULL, prescriptiontime datetime DEFAULT NULL, orderprice float DEFAULT NULL, ispaid tinyint(1) DEFAULT NULL, drugSpecifications varchar(45) DEFAULT NULL, orderallprice float DEFAULT NULL, takeMedicine varchar(45) DEFAULT NULL, Frequency varchar(45) DEFAULT NULL, TotalOrder int DEFAULT NULL, patiid varchar(45) NOT NULL, PRIMARY KEY (orderid)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
